function GamePacketSender:sendBedWarRefreshResult(rakssid, commonItem, coreItem, refreshPrice, lotteryPrice)
    local rewardId = ""
    local allItem = commonItem
    for _, reward in pairs(coreItem or {}) do
        table.insert(allItem, 1, reward)
    end

    for _, Id in pairs(allItem) do
        rewardId = rewardId .. "#" .. tostring(Id)
    end

    local params = {
        reward = rewardId,
        refreshPrice = refreshPrice,
        lotteryPrice = lotteryPrice,
    }
    local data = DataBuilder.new():fromTable(params):getData()

    PacketSender:sendLuaCommonData(rakssid, "LotteryRefreshResult", data)
end

