function GamePacketSender:sendSignalBomb(senderId, pos, id, teamId)
    local params = {
        posX = math.floor(pos.x * 10) / 10,
        posY = math.floor(pos.y * 10) / 10,
        posZ = math.floor(pos.z * 10) / 10,
        id = id,
        senderId = senderId
    }
    local data = DataBuilder.new():fromTable(params):getData()
    local players = PlayerManager:getPlayers()
    for _, player in pairs(players) do
        if player.teamId == teamId then
            PacketSender:sendLuaCommonData(player.rakssid, "SendSignal", data)
        end
    end
end

