function GamePacketSender:broadcastSound(soundType, pos)
    local players = PlayerManager:getPlayers()
    if pos then
        for _, player in pairs(players) do
            GamePacketSender:sendPlaySound3d(player.rakssid, soundType, pos)
        end
    else
        for _, player in pairs(players) do
            GamePacketSender:sendPlaySound(player.rakssid, soundType)
        end
    end
end

